  media_library = jsonb_set(
    COALESCE(e.media_library, '{}'::jsonb),
    '{clinical_or_sport_science_references}',
    COALESCE(
      (
        SELECT jsonb_agg(elem ORDER BY elem)
        FROM (
          SELECT DISTINCT elem
          FROM (
            SELECT jsonb_array_elements_text(
              COALESCE(e.media_library->'clinical_or_sport_science_references', '[]'::jsonb)
            ) AS elem
            UNION ALL
            SELECT unnest(ARRAY['https://www.youtube.com/watch?v=oWBFjZBCIu0', 'https://www.youtube.com/watch?v=COk5Ytr6jDo', 'https://www.youtube.com/watch?v=2B4kvtpwfsc', 'https://www.youtube.com/watch?v=dGZISJMPGNA', 'https://www.youtube.com/watch?v=sxM-cXCxsrM']::text[]) AS elem
          ) combined
          WHERE elem IS NOT NULL AND btrim(elem) <> ''
        ) deduped
      ),
      '[]'::jsonb
    ),
    true
  ),
  updated_at = now()
WHERE e.id = 15939;

